shapes.frame_eqs_str:
tex_capture  = q1;

saw = saw - 0.001*bass;
saw = if(below(saw,0.1),0.6,saw);

tex_zoom = saw;

tex_capture  = q2;

saw = saw - 0.001*bass;
saw = if(below(saw,0.1),0.6,saw);

tex_zoom = saw;

waves.point_eqs_str:
speed = bass*0.1;
v = sample*10000 + value2*bass*0.1;

//state 0 elipse
xs = xs + (equal(0,q1))*sin(v*1)*speed*atan(v*1.51);
ys = ys + (equal(0,q1))*sin(v*1)*speed;

x = 0.5 + 0.5*sin(xs*0.1)*cos(time*2 + xs);
y = 0.5 + 0.5*sin(ys*0.1)*cos(time*2.1 + xs);

y = y - sample*0.1;

x = x*0.6 + 0.2;
y = y + bass*0.1;
y = y*0.8;

r = 0.5 + 0.5*sin(time*6.22) + 0.1;
g = 0.4 + 0.4*sin(time*5.307);
b = 0.4 + 0.4*sin(time*4.959)*x;

xs = if(above(xs,1000),0 ,xs);
ys = if(above(ys,1000),0 ,ys);
